#include <stdio.h>

void funcA(int n);
void funcB(int n);

void funcA(int n) {
    if (n <= 0) return;
    printf("%d ", n);
    funcB(n - 1);
    printf("%d ", n);
}

void funcB(int n) {
    if (n <= 0) return;
    printf("%d ", n);
    funcA(n % 2);
}

int main() {
    funcA(4);
    return 0;
}

#include <stdio.h>

int func(int x) {
    if (x <= 0) return 0;
    if (x == 1) return 1;
    return func(x - 2) + func(x - 1);
}

int main() {
    printf("%d", func(4));
    return 0;
}
